        for i, todo in enumerate(todos):
            print(f"{i + 1}: {todo}")

    elif command == "remove":
        idx = int(sys.argv[2])
        todos = load_todos()
        # 1-based index, so valid range is [1, len]
        if 1 <= idx <= len(todos):
            todos.pop(idx - 1)
            save_todos(todos)
        # 超出范围时静默忽略

if __name__ == "__main__":
    main()

